import '../lib/license_gate.dart';
import '../lib/scan_report_adapter.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  const upgradedPayload = r'''
{
  "document": {
    "artifacts": [
      {
        "coordinates": {"name": "layout-engine", "version": "5.0.0"},
        "license": {"expression": "GPL-3.0-only OR (Apache-2.0 AND MIT)"},
        "scope": "runtime"
      },
      {
        "coordinates": {"name": "font-reader", "version": "2.4.1"},
        "license": {"expression": "(BSD-3-Clause AND LicenseRef-Internal) OR GPL-2.0-only"},
        "scope": "runtime"
      },
      {
        "coordinates": {"name": "snapshot-tool", "version": "1.0.0"},
        "license": {"expression": "LicenseRef-Internal"},
        "scope": "development"
      }
    ]
  }
}
''';

  final records = ScanReportAdapter().decode(upgradedPayload);
  check(records.length == 3, 'keeps all upgraded dependency records');

  final violations = LicenseGate(<String>{
    'Apache-2.0',
    'MIT',
    'BSD-3-Clause',
  }).violations(records);
  check(
    violations.length == 1,
    'evaluates alternatives, conjunctions, and scope',
  );
  check(
    violations.single.name == 'font-reader',
    'reports only the unsatisfied runtime expression',
  );

  print('final tests passed');
}
